parameters.toolDescription:
Loads the full property record, session, transfer history, and existing extractions from the database.
Call this before calling Title Attorney. Pass the returned data in the Title Attorney call.
Input: { property_id }
Output: { property, session, appraiser_transfer_history, extractions }

parameters.jsonBody:
={{ (function() {
  try {
    const raw = $('Root Owner Research').first().json.output || '';
    const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
    const m = cleaned.match(/\{[\s\S]*\}/);
    const parsed = JSON.parse(m ? m[0] : cleaned);
    const sess = $('Create Heir Session').first().json;
    const name = parsed.root_decedent_name || parsed.matched_identity?.full_name || sess.root_decedent_name || 'Unknown';
    return {
      session_id:        sess.session_id,
      property_id:       sess.property_id,
      input_name:        name,
      relationship_hint: 'root_decedent',
      level:             0,
      research_phase:    'complete',
      vital_status:      parsed.vital_status || 'deceased',
      matched_identity:  parsed.matched_identity || {},
      obituary_url:      parsed.obituary_url || '',
      obituary_text:     parsed.obituary_text || '',
      deceased_facts: {
        date_of_death:           parsed.date_of_death || '',
        marital_status_at_death: parsed.marital_status_at_death || '',
        surviving_spouse_name:   parsed.surviving_spouse_name || '',
        estate_filed:            parsed.estate_filed,
        had_will:                parsed.had_will,
        family_alive_at_death:   parsed.cascade_relatives || [],
      },
      cascade_relatives: parsed.cascade_relatives || [],
    };
  } catch(e) {
    const sess = $('Create Heir Session').first().json;
    return { session_id: sess.session_id, property_id: sess.property_id, input_name: sess.root_decedent_name || 'Unknown', level: 0, research_phase: 'complete', vital_status: 'deceased' };
  }
})() }}

={{ (function() {
  try {
    const raw = $('Root Owner Research').first().json.output || '';
    const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
    const m = cleaned.match(/\{[\s\S]*\}/);
    const parsed = JSON.parse(m ? m[0] : cleaned);
    const sess = $('Create Heir Session').first().json;
    const relatives = parsed.cascade_relatives || [];
    return {
      session_id: sess.session_id,
      property_id: sess.property_id,
      depth: 1,
      persons: relatives.map(r => ({
        name: r.name,
        relationship_hint: r.relationship_hint || 'child',
        maiden_name: r.maiden_name || null,
        depth: 1,
      })),
    };
  } catch(e) {
    const sess = $('Create Heir Session').first().json;
    return { session_id: sess.session_id, property_id: sess.property_id, persons: [], _error: e.message };
  }
})() }}

={{ (function() {
  try {
    const q = $('Queue Initial Relatives').first().json;
    const sess = $('Create Heir Session').first().json;
    const firstQueued = (q.queued || [])[0] || null;
    if (!firstQueued) {
      return {
        session_id: sess.session_id,
        property_id: sess.property_id,
        county: sess.county || '',
        person_name: '',
        relationship_hint: '',
        queue_id: null,
        _no_persons: true,
      };
    }
    return {
      session_id: sess.session_id,
      property_id: sess.property_id,
      county: sess.county || '',
      person_name: firstQueued.person_name,
      relationship_hint: firstQueued.person_name || 'child',
      maiden_name: firstQueued.maiden_name || '',
      queue_id: firstQueued.queue_id,
    };
  } catch(e) {
    const sess = $('Create Heir Session').first().json;
    return {
      session_id: sess.session_id,
      property_id: sess.property_id,
      county: sess.county || '',
      person_name: '',
      relationship_hint: '',
      queue_id: null,
      _error: e.message,
    };
  }
})() }}

